import{_ as e,o as s,c as t,a2 as i}from"./chunks/framework.D6hBiDio.js";const u=JSON.parse('{"title":"APK Installation","description":"Install Tailscale on OpenWrt 25.12+ using the APK package manager — step by step","frontmatter":{"title":"APK Installation","description":"Install Tailscale on OpenWrt 25.12+ using the APK package manager — step by step"},"headers":[],"relativePath":"en/guide/apk-setup.md","filePath":"en/guide/apk-setup.md","lastUpdated":1784575673000}'),n={name:"en/guide/apk-setup.md"};function l(o,a,r,p,d,h){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="apk-installation-openwrt-25-12" tabindex="-1">APK Installation (OpenWrt 25.12+) <a class="header-anchor" href="#apk-installation-openwrt-25-12" aria-label="Permalink to &quot;APK Installation (OpenWrt 25.12+)&quot;">​</a></h1><p>This guide is for <strong>OpenWrt 25.12 or later</strong>, which uses the <strong>APK</strong> package manager.<br> If you have an older version, go to <a href="/openwrt-tailscale/en/guide/opkg-setup.html">OPKG Installation</a>.</p><h2 id="step-1-download-the-public-key" tabindex="-1"><strong>Step 1:</strong> Download the public key <a class="header-anchor" href="#step-1-download-the-public-key" aria-label="Permalink to &quot;**Step 1:** Download the public key&quot;">​</a></h2><h3 id="add-the-repository-public-key-to-the-trusted-keyring" tabindex="-1">Add the repository public key to the trusted keyring: <a class="header-anchor" href="#add-the-repository-public-key-to-the-trusted-keyring" aria-label="Permalink to &quot;Add the repository public key to the trusted keyring:&quot;">​</a></h3><p>Run the following command on your OpenWrt device:</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apk/keys/gunanovo@github.io.pub</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://gunanovo.github.io/openwrt-tailscale/key-build.rsa.pub</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Or manually download the public key file to /etc/apk/keys/ on your OpenWrt device.</p><h2 id="step-2-add-the-repository" tabindex="-1"><strong>Step 2:</strong> Add the repository <a class="header-anchor" href="#step-2-add-the-repository" aria-label="Permalink to &quot;**Step 2:** Add the repository&quot;">​</a></h2><h3 id="add-the-repository-to-your-openwrt-configuration" tabindex="-1">Add the repository to your OpenWrt configuration: <a class="header-anchor" href="#add-the-repository-to-your-openwrt-configuration" aria-label="Permalink to &quot;Add the repository to your OpenWrt configuration:&quot;">​</a></h3><p>Run the following command on your OpenWrt device:</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://gunanovo.github.io/openwrt-tailscale/$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apk/arch)/packages.adb&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apk/repositories.d/customfeeds.list</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Or manually edit /etc/apk/repositories.d/customfeeds.list and add the following:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://gunanovo.github.io/openwrt-tailscale/{your-device-architecture}/packages.adb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Replace {your-device-architecture} with your device architecture. Use cat /etc/apk/arch to find it.</p><h2 id="step-3-install-tailscale" tabindex="-1"><strong>Step 3:</strong> Install Tailscale <a class="header-anchor" href="#step-3-install-tailscale" aria-label="Permalink to &quot;**Step 3:** Install Tailscale&quot;">​</a></h2><h3 id="choose-your-preferred-method-to-install-tailscale" tabindex="-1">Choose your preferred method to install Tailscale: <a class="header-anchor" href="#choose-your-preferred-method-to-install-tailscale" aria-label="Permalink to &quot;Choose your preferred method to install Tailscale:&quot;">​</a></h3><h4 id="command-line" tabindex="-1">Command line: <a class="header-anchor" href="#command-line" aria-label="Permalink to &quot;Command line:&quot;">​</a></h4><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Update package lists</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install tailscale</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tailscale</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h4 id="web-ui" tabindex="-1">Web UI: <a class="header-anchor" href="#web-ui" aria-label="Permalink to &quot;Web UI:&quot;">​</a></h4><ol><li>Go to System → Software;</li><li>Click Update lists to refresh packages;</li><li>Search for &quot;tailscale&quot;;</li><li>Install &quot;tailscale&quot;;</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The <code>&quot;failed log upload&quot;</code> message during installation is expected and can be safely ignored.</p></div><p><strong>Done.</strong> Now configure Tailscale:</p><p><a href="/openwrt-tailscale/en/guide/post-install.html">Post-Installation Configuration →</a></p>`,23)])])}const k=e(n,[["render",l]]);export{u as __pageData,k as default};
